snippets.C0615:
-- [PostgreSQL SQL] C0615 · Celsius a Fahrenheit (extra #95) (Básico, Fórmulas)
WITH params AS (SELECT 0::double precision AS c)
SELECT ((c * 9.0/5.0) + 32) AS result FROM params;

snippets.C0616:
-- [PostgreSQL SQL] C0616 · Fahrenheit a Celsius (extra #96) (Intermedio, Fórmulas)
WITH params AS (SELECT 0::double precision AS f)
SELECT ((f - 32) * 5.0/9.0) AS result FROM params;

snippets.C0617:
-- [PostgreSQL SQL] C0617 · Área círculo (extra #97) (Básico, Fórmulas)
WITH params AS (SELECT 0::double precision AS r)
SELECT (pi() * r * r) AS result FROM params;

snippets.C0618:
-- [PostgreSQL SQL] C0618 · Circunferencia (extra #98) (Básico, Fórmulas)
WITH params AS (SELECT 0::double precision AS r)
SELECT (2 * pi() * r) AS result FROM params;

snippets.C0619:
-- [PostgreSQL SQL] C0619 · Volumen esfera (extra #99) (Intermedio, Fórmulas)
WITH params AS (SELECT 0::double precision AS r)
SELECT ((4.0/3.0) * pi() * r * r * r) AS result FROM params;

snippets.C0620:
-- [PostgreSQL SQL] C0620 · Descuento (extra #100) (Básico, Fórmulas)
WITH params AS (SELECT 0::double precision AS precio, 0::double precision AS pct)
SELECT (precio * (1 - (pct / 100))) AS result FROM params;

