snippets.C0675:
-- C0675 · Migración simple (schema versioning) (Intermedio, Base de datos)
-- PostgreSQL: tabla de migraciones + migración idempotente v1
CREATE TABLE IF NOT EXISTS schema_migrations (
  version text PRIMARY KEY,
  applied_at timestamptz NOT NULL DEFAULT now()
);

-- v1
CREATE TABLE IF NOT EXISTS customers (
  id bigserial PRIMARY KEY,
  name text NOT NULL,
  email text NULL
);

INSERT INTO schema_migrations(version) VALUES ('v1')
ON CONFLICT (version) DO NOTHING;

snippets.C0679:
-- C0679 · Deadlock/locking demo (2 sesiones) (Avanzado, Base de datos)
-- Ejecutar en 2 sesiones.
-- Pre:
-- CREATE TABLE IF NOT EXISTS demo_lock(id int primary key, val int);
-- INSERT INTO demo_lock(id,val) VALUES (1,10),(2,20) ON CONFLICT DO NOTHING;

-- SESIÓN A
BEGIN;
  UPDATE demo_lock SET val = val + 1 WHERE id = 1;
  SELECT pg_sleep(3);
  UPDATE demo_lock SET val = val + 1 WHERE id = 2;
COMMIT;

-- SESIÓN B
BEGIN;
  UPDATE demo_lock SET val = val + 1 WHERE id = 2;
  SELECT pg_sleep(3);
  UPDATE demo_lock SET val = val + 1 WHERE id = 1;
COMMIT;
